var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미의 문화를 빛내는 자리에 함께해 주어 고맙습니다. 학우 여러분.","JPN":"生徒の皆様、\\nアカデミーの栄えある伝統的なこの場にご参加いただき、ありがとうございます。","ENG":"My fellow students, thank you for coming here to share the Academy's culture together.","TWN":"謝謝各位同學來到這裡，一起為學院的文化增添光彩。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"우리 아카데미에서 운동회란, 단합을 통해 학우들에게 협동정신을 심어주는 행사입니다.","JPN":"我がアカデミーにおいて運動会とは、団結することによって生徒の協同精神を養う行事です。","ENG":"The Field Day is an occasion for us to learn how to cooperate with each other.","TWN":"我們學院的運動會旨在透過團結讓同學們學習到合作精神。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"동시에 우승이라는 목표를 위해 선의의 경쟁과 성장을 도모하는 교육의 장이기도 하죠.","JPN":"同時に、優勝という目標のために善き競争と成長を図る教育の場でもあります。","ENG":"It's also a valuable opportunity in which we can improve ourselves through fair competition.","TWN":"同時它也是以奪冠為目標，追求善意競爭與成長的一種教育方式。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그러니 부디 이 자리에서 지금까지 쌓아온 노력의 결실을 아낌없이 증명해 주시기를 바라며......","JPN":"ですから、ぜひこの場で今まで積み重ねてきた努力の成果を惜しみなく発揮していただき……","ENG":"In order to achieve these purposes, I'd like you all to make your best efforts to show your abilities...","TWN":"所以，希望大家在這裡不遺餘力地證明自己過去累積的努力成果……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"흐아암......","JPN":"ふわぁ～","ENG":"*Yawn*","TWN":"哈啊啊……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"회장...... 다들 훈화가 지루해서 죽으려고 하는 거 같아......","JPN":"会長……みんな演説がつまらなくて辛そうな顔しているよ……","ENG":"Yen... Everyone's dying because of your boring speech...","TWN":"會長……大家好像聽的有些厭煩了zzz……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그래요? 저도 모르게 들떠 있었나 보네요.","JPN":"そうですか？　私もつい浮かれてしまったようですね。","ENG":"Really? I'm sorry I got carried away.","TWN":"是嗎？看來，我也在不知不覺中興奮起來了。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_02"},{"id":"L14_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"본론으로 들어가죠. 운동회에서 모든 선수는 홍팀과 청팀으로 나뉘어 협동하고 경쟁하게 됩니다.","JPN":"本題に入りましょう。運動会ではすべての選手は赤組と青組に分かれ、協力して競うことになります。","ENG":"Let's cut to the chase. All players will be cooperating or competing on two teams: Red Team and Blue Team.","TWN":"言歸正傳，運動會上所有選手將分成紅、藍兩隊。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"각 경기마다 선수 각자의 개인점수와 팀 점수를 얻고, 그렇게 두 점수를 합산해 최고점을 얻은 선수가 우승하게 되죠.","JPN":"競技ごとに選手各自の個人点数とチーム点数を獲得し、\\nその2つの点数を合算して最高点を得た選手が優勝となります。","ENG":"In each game, everyone will earn both individual and team points. Whoever gets the highest total points will win the game.","TWN":"每場比賽獲得選手的個人分數和團隊分數，兩個分數加總，拿到最高分的選手獲勝。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"첫 번째 경기는 <color=#ffd34c>꼬리 잡기</color>.","JPN":"最初の試合は<color=#ffd34c>しっぽ取りゲーム</color>。","ENG":"The first game is called <color=#ffd34c>Catch the Tail</color>.","TWN":"第一場比賽是<color=#ffd34c>抓尾巴</color>。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"자세한 내용은 특별히 선별된 진행 요원이 전달해 줄 겁니다.","JPN":"詳しいルールは、この度特別に選別された進行スタッフからお伝えします。","ENG":"The special host here will tell you the details.","TWN":"具體內容將由特別邀請的主持人向大家介紹。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"모두들 안녕하세요!","JPN":"みなさん、こんにちは！","ENG":"Hello, everyone!","TWN":"大家好！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"올해 운동회에서 홍팀 응원과 함께 진행을 맡게 된 양하림이에요!","JPN":"今年の運動会で赤組の応援と進行役を務めることになったホシノ・ウサギです！","ENG":"I'm Yang Harim, charged with hosting this year's Field Day and cheering for the Red Team.","TWN":"我是在今年運動會上支持紅隊的主持人楊夏琳！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"꼬리잡기의 룰은 간단해요! 서로 다른 선수의 허리에 달린 스카프를 떼기만 하면 되거든요!","JPN":"しっぽ取りゲームのルールは簡単です！　他の選手の腰に付いたしっぽ、つまりスカーフを取るだけ！","ENG":"The rules of Catch the Tail are simple: just remove the scarf hanging from someone else's waist!","TWN":"抓尾巴的規則非常簡單！只要搶奪不同選手綁在腰上的紗巾就可以了！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"스카프가 떨어지면 탈락! 경기 진행은 선수 중 절반의 스카프가 떨어질 때까지!","JPN":"スカーフが取られたら脱落！　試合は選手の半数のスカーフが取られるまで続きます！","ENG":"If you lose your scarf, you'll be disqualified. The game will continue until half of the players lose their scarves.","TWN":"紗巾掉落者就淘汰！半數的選手紗巾如果都掉落，就代表這場比賽結束並開始進行結果的統計！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"마지막까지 남은 선수들이 모은 꼬리를 합산해서 더 많은 팀이 승리합니다!","JPN":"最後まで残った選手たちが集めたしっぽを合計して、多い方のチームが勝利となります！","ENG":"And the team whose survivors are holding the most tails wins!","TWN":"統計最後剩下的選手拿到的尾巴數量，由尾巴數量最多的隊伍獲勝！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"꼬리를 떼서 점수를 얻는 것도 중요하지만, 꼬리를 잃는 순간 자기가 모은 점수도 잃게 되니 조심해야겠죠?","JPN":"しっぽを取って点数を稼ぐのも大事ですが、しっぽを取られた瞬間に自分が貯めた点数も無くなってしまうので、気を付けないとですよ！","ENG":"It's important that you earn points by removing other people's tails, but be careful, all your points will be forfeited the moment you lose your tail!","TWN":"扯下別人的尾巴得分固然重要，但失去尾巴的瞬間，自己拿到的分數也會一併失去，所以大家一定要小心嘍！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"흥, 너무 간단해서 한숨이 나올 정도네.","JPN":"ふん、簡単すぎてあくびが出るわ。","ENG":"Hmpf, this game is so simple that it makes me want to sigh.","TWN":"哼，這也太簡單了吧。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"<color=#ffd34c>잡히지 않고, 잡는다.</color> 그거면 충분하잖아?","JPN":"<color=#ffd34c>捕まらずに、捕まえる。</color>それだけで十分でしょ？","ENG":"<color=#ffd34c>Catch, and don't get caught.</color> That's all, isn't it?","TWN":"<color=#ffd34c>保住自己的尾巴，抓別人的尾巴。</color>這兩句話不就明白了？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"......그렇게 방심하다가 큰 코 다칠걸?","JPN":"……そうやってなめてたら痛い目にあうよ？","ENG":"You'd better not let your guard down, or you'll be sorry.","TWN":"……你那麼大意可是會吃大虧的。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"실력이 좋을수록 견제를 받기 마련이거든.","JPN":"実力のある人ほど、けん制を受けるものだからね。","ENG":"The better you are, the more you'll be checked.","TWN":"因為實力越好，受到的牽制越多。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"견제 따윌 무서워하는 건 네 수준에서나 있는 일이지.","JPN":"けん制なんかにビビるのはあんたぐらい低レベルなやつの話でしょ。","ENG":"Only losers like you are afraid of being checked.","TWN":"像你這樣的才會害怕什麼牽制。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"애초에 레벨이 다른 상대에게 그런 얕은 수는 안 통해.","JPN":"そもそも格が違う相手にそんな手は通じないわ。","ENG":"But that's not going to fly with me, who's on a completely different level from the rest of you.","TWN":"我們根本不在同一個準水上，像那種小伎倆根本就行不通。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"그래, 나처럼 월등한 엘리트에겐 말이야! 아하하핫!","JPN":"ええ、私みたいなケタ違いのエリートにはね！　アハハッ！","ENG":"I'm an elite! Ah hah hah hah!","TWN":"沒錯，就是像我這種優秀的精英！啊哈哈哈！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"확실히 학생회장을 제외하면 아카데미 최강의 엘리트라더니, 자신감이 대단한데?","JPN":"生徒会長を除けばアカデミー最強のエリートっていう噂どおり、自信がとてもあるみたいね。","ENG":"I hear you're the second best in the Academy after the Student President. Is that why you're so confident?","TWN":"聽說你是學院裡除了學生會長最厲害的精英，果然信心十足啊？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"뭐... 뭐야, 넌? 처음 보는 얼굴인데?","JPN":"あ、あんたは誰？　初めてみる顔みたいだけど？","ENG":"W-who are you? You don't look familiar.","TWN":"妳…妳誰啊？好像從沒見過妳？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"복장을 보니 청팀 선수 같은데......","JPN":"その服装は青組の選手のようですが……","ENG":"Judging by your uniform, you must be on the Blue Team...","TWN":"從服裝來看，好像是藍隊的選手……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"맞아! 그러고 보니 운동회에 참가 신청을 한 임시 편입생들 중에서 본 적이 있어!","JPN":"あ！　そういえば運動会に参加申請をした臨時編入生の中で見た！","ENG":"Oh, right! I saw you among the temporary transfer students that applied for the Field Day!","TWN":"沒錯！我想起來了，我在申請參加運動會的臨時插班生中見過她！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"임시 편입생? 그건 또 뭐야?","JPN":"臨時編入生？　何それ？","ENG":"Temporary transfer student? What's that?","TWN":"臨時插班生？那又是什麼鬼？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이번 운동회의 우승 상품이 무려, 누구나 탐낼 법한 <color=#ffd34c>소원 구슬</color>이잖아.","JPN":"今回の運動会の優勝賞品は、誰もが欲しがるような<color=#ffd34c>願い玉</color>でしょ。","ENG":"You know everyone has their eye on today's winning prize, the <color=#ffd34c>Wishing Ball</color>.","TWN":"這次運動會的優勝獎品不是那個足以讓所有人都夢寐以求的<color=#ffd34c>許願珠</color>嘛。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이 기회에 아카데미 홍보도 할 겸, 예비 입학을 전제로 외부인 카운터들의 참가 신청도 받아주기로 했거든.","JPN":"せっかくだからアカデミー広報も兼ねて、予備入学を前提に外部のカウンターの参加申し込みも受け付けることにしたの。","ENG":"The Academy has decided to advertise itself by accepting external Counters as players, on the basis that they'll enter the Academy after the event.","TWN":"為了趁此機會宣傳學院，以入學為前提，允許外部的制裁者參加此次運動會。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"훗, 그럼 결국 어중이떠중이란 뜻이네.","JPN":"ふっ、つまりは烏合の衆みたいなもんか。","ENG":"Hah, so she's a mere nobody.","TWN":"呼，原來是一群“阿貓阿狗”啊。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"좋아. 아카데미는 처음인 것 같으니까 충고 하나 해 줄게.","JPN":"よし、アカデミーは初めてのようだから一つアドバイスしてやるわ。","ENG":"Alright, since you're new to the Academy, let me give you some advice.","TWN":"好吧，看在你剛來學院的份上，我就給你個忠告。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L50_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"소원 구슬은 내 거야. 그러니까 쓸데없이 덤비지 말고 지금이라도 포기하시지.","JPN":"願い玉は私がもらう。だから余計なことはせずに今からでも諦めたほうがいいわよ。","ENG":"The Wishing Ball is mine. So, save yourself the grief and give up now.","TWN":"許願珠是我的，你就不要白費力氣了，趁早放棄吧。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"그렇지 않으면 <color=#ffd34c>아카데미 최강 2종 슬레이어</color>의 실력을 뼈저리게 느끼게 될 테니까.","JPN":"じゃないと<color=#ffd34c>アカデミー最強の第2種スレイヤー</color>との実力の差を骨の髄まで思い知らされることになるから。","ENG":"Or the <color=#ffd34c>Academy's best Category 2 Slayer</color> will show you what she can do.","TWN":"否則我會讓你完完整整的體會到<color=#ffd34c>學院最強2級屠戮者</color>的實力。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"오호호홋!!","JPN":"オホホホホッ！！","ENG":"Ah hah hah hah!","TWN":"哇哈哈哈哈！！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"후훗. 미나랑은 다른 의미로 날 불타오르게 만드는 재주가 있네, 너는.","JPN":"ふふ、ミナとは違う意味で私を燃え上がらせる才能があるじゃない。","ENG":"Hah hah. You spur me on, although differently from how Mina does it.","TWN":"呵呵，雖然方式不同，但是你跟米娜一樣有讓我熱血沸騰的本事呢。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"충고는 고맙게 받아들일게. 물론 포기할 마음은 없지만.","JPN":"アドバイスありがとう。もちろん諦めるつもりはないけど。","ENG":"Thank you for your advice. But I'm not going to give up.","TWN":"謝謝你的忠告，不過我是不會放棄的。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"그럼 경기에서 봐. 아카데미 최강.","JPN":"それじゃあ試合で会おうね、アカデミー最強さん。","ENG":"See you in the game, Academy's best.","TWN":"那就賽場上見吧，學院最強。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"다들 준비됐나요?","JPN":"みんな、準備はいいですか？","ENG":"Is everyone ready?","TWN":"大家都準備好了嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"자, 그럼! 모두 제자리에~","JPN":"では、せーのっ！","ENG":"Alright, then! Ready, get set...","TWN":"好了！各就各位~"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARIM_REBBIT_SPORTS_BG","text":{"KOREA":"경기~ 시~작!","JPN":"試合スタ～ト！","ENG":"Go!","TWN":"預備~開~始！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_SPORTS_BG","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};